def checkReverse(arr, n):
    if n == 1:
        return True
    # Find the longest initial strictly increasing segment.
    i = 1
    while i < n and arr[i - 1] < arr[i]:
        i += 1
    if i == n:
        return True
    # Set j to the current i (and then increment i, mimicking i++ in Java).
    j = i
    i += 1
    # Process the segment where the array is strictly decreasing.
    while j < n and arr[j] < arr[j - 1]:
        # Check the additional condition: if the current value is less than the element
        # before the increasing segment (at index i-2).
        if i > 1 and arr[j] < arr[i - 2]:
            return False
        j += 1
    if j == n:
        return True
    # Set k to the current j.
    k = j
    # Check if the element at k is not less than the last element of the decreasing segment.
    if k < n and arr[k] < arr[i - 1]:
        return False
    # Verify the remainder of the array is non-decreasing.
    while k < n:
        if k > 1 and arr[k] < arr[k - 1]:
            return False
        k += 1
    return True

