def findSubsequenceCount(S, T):
    m = len(T)
    n = len(S)
    if m > n:
        return 0
    # Create a (m+1) x (n+1) DP table filled with zeros
    mat = [[0] * (n + 1) for _ in range(m + 1)]
    # Base case: An empty T is a subsequence of any prefix of S.
    for j in range(n + 1):
        mat[0][j] = 1
    # Fill the DP table
    for i in range(1, m + 1):
        for j in range(1, n + 1):
            if T[i - 1] != S[j - 1]:
                mat[i][j] = mat[i][j - 1]
            else:
                mat[i][j] = mat[i][j - 1] + mat[i - 1][j - 1]
    return mat[m][n]

