def num_of_inc_subseq_of_size_k(arr, n, k):
    # Create a 2D list initialized with zeros: dp[l][i] refers to number of increasing subsequences
    # of length l+1 ending at index i.
    dp = [[0] * n for _ in range(k)]
    total_sum = 0
    # Base case: Subsequences of length 1
    for i in range(n):
        dp[0][i] = 1
    # Build dp for subsequences of length > 1
    for l in range(1, k):
        for i in range(l, n):
            dp[l][i] = 0
            for j in range(l - 1, i):
                if arr[j] < arr[i]:
                    dp[l][i] += dp[l - 1][j]
    # Sum up all increasing subsequences of length k
    for i in range(k - 1, n):
        total_sum += dp[k - 1][i]
    return total_sum

