def countP(n, k):
    # Create a 2D list (dp) with dimensions (n+1) x (k+1) initialized to 0
    dp = [[0] * (k + 1) for _ in range(n + 1)]
    # Set all dp[i][0] = 0 for i in 0..n (already 0 by initialization)
    for i in range(n + 1):
        dp[i][0] = 0
    # Set all dp[0][j] = 0 for j in 0..k (already 0 by initialization)
    for j in range(k + 1):
        dp[0][j] = 0
    # Fill dp table using recurrence relation
    for i in range(1, n + 1):
        for j in range(1, k + 1):
            if j == 1 or i == j:
                dp[i][j] = 1
            else:
                dp[i][j] = j * dp[i - 1][j] + dp[i - 1][j - 1]
    return dp[n][k]

