def countPS(s: str) -> int:
    N = len(s)
    # Create a (N+1)x(N+1) 2D list initialized with zeros.
    cps = [[0] * (N + 1) for _ in range(N + 1)]
    # Every single character is a palindrome subsequence.
    for i in range(N):
        cps[i][i] = 1
    # Build the table. L is the length of substring.
    for L in range(2, N + 1):
        for i in range(N):
            k = L + i - 1
            if k < N:
                # If the characters are same, add 1 to count.
                if s[i] == s[k]:
                    cps[i][k] = cps[i][k - 1] + cps[i + 1][k] + 1
                else:
                    cps[i][k] = cps[i][k - 1] + cps[i + 1][k] - cps[i + 1][k - 1]
    return cps[0][N - 1]

