def eggDrop(n, k):
    # Create a DP table with (n+1) rows and (k+1) columns
    eggFloor = [[0] * (k + 1) for _ in range(n + 1)]
    # Base cases:
    # With one floor, one trial, and with zero floor, zero trials.
    for i in range(1, n + 1):
        eggFloor[i][1] = 1
        eggFloor[i][0] = 0
    # With one egg and j floors, j trials (worst case: try every floor)
    for j in range(1, k + 1):
        eggFloor[1][j] = j
    # Fill the rest of the table using the optimal substructure property.
    # i: number of eggs, j: number of floors.
    for i in range(2, n + 1):
        for j in range(2, k + 1):
            eggFloor[i][j] = float('inf')
            # Try dropping from every floor x from 1 to j and choose the minimum of the worst-case scenario.
            for x in range(1, j + 1):
                res = 1 + max(eggFloor[i - 1][x - 1], eggFloor[i][j - x])
                if res < eggFloor[i][j]:
                    eggFloor[i][j] = res
    return eggFloor[n][k]

