def minPalPartition(s: str) -> int:
    n = len(s)
    # Create a 2D list for palindrome checks (P) and cuts (C)
    P = [[False] * n for _ in range(n)]
    C = [[0] * n for _ in range(n)]
    # Base initialization: single characters are palindromes.
    for i in range(n):
        P[i][i] = True
        C[i][i] = 0
    # L is the length of substring.
    for L in range(2, n + 1):
        for i in range(n - L + 1):
            j = i + L - 1
            if L == 2:
                P[i][j] = (s[i] == s[j])
            else:
                P[i][j] = (s[i] == s[j]) and P[i + 1][j - 1]
            # If s[i...j] is a palindrome, no cut is needed.
            if P[i][j]:
                C[i][j] = 0
            else:
                # Initialize with a large number; alternatively, n would be a safe upper bound.
                C[i][j] = float('inf')
                for k in range(i, j):
                    C[i][j] = min(C[i][j], C[i][k] + C[k + 1][j] + 1)
    return C[0][n - 1]

