def findMaxGCD(arr, n):
    # Find the maximum value in the array
    high = max(arr) if n > 0 else 0
    # Create a list for counting divisors, with indices from 0 to high
    divisors = [0] * (high + 1)
    # Count the number of array elements divisible by each divisor
    for num in arr:
        # Iterate from 1 to sqrt(num)
        limit = int(math.sqrt(num))
        for j in range(1, limit + 1):
            if num % j == 0:
                divisors[j] += 1
                # Check if j and num // j are different divisors
                if j != num // j:
                    divisors[num // j] += 1
    # Traverse from highest possible divisor downwards and return the first
    # divisor that divides more than 1 element, which is our maximum GCD.
    for i in range(high, 0, -1):
        if divisors[i] > 1:
            return i
    return 1

