def kthLargestSum(arr, n, k):
    # Build prefix sum array where prefix[i] is the sum of arr[0] to arr[i-1]
    prefix = [0] * (n + 1)
    prefix[0] = 0
    for i in range(1, n + 1):
        prefix[i] = prefix[i - 1] + arr[i - 1]
    # Use a min-heap to keep track of the k largest subarray sums.
    Q = []
    # Iterate over all subarrays with starting index i and ending index j
    for i in range(1, n + 1):
        for j in range(i, n + 1):
            x = prefix[j] - prefix[i - 1]
            if len(Q) < k:
                heapq.heappush(Q, x)
            else:
                if Q[0] < x:
                    heapq.heappop(Q)
                    heapq.heappush(Q, x)
    return Q[0]

