def subsequence(s, n, k):
    # s: input string or list of characters
    # n: length of s
    # k: threshold value
    # We'll collect the output characters in list t
    t = []
    last = 0  # starting index for searching in s
    # Iterate over characters from 'z' down to 'a'
    for ch in reversed('abcdefghijklmnopqrstuvwxyz'):
        cnt = 0
        # Count occurrences of ch in s starting from index last
        for i in range(last, n):
            if s[i] == ch:
                cnt += 1
        # If we have at least k occurrences, add all these occurrences to t
        if cnt >= k:
            new_last = last
            for i in range(last, n):
                if s[i] == ch:
                    t.append(ch)
                    new_last = i
            # Update the starting point for the next character
            last = new_last
    # Return the resulting subsequence as a string
    return ''.join(t)

