    # Fill the first column by accumulating the values
    for i in range(1, N):
        dp[i][0] = mat[i][0] + dp[i - 1][0]
    # Fill the rest of the dp table
    for i in range(1, N):
        # We iterate j from 1 up to the minimum of i+1 and N
        for j in range(1, min(i + 1, N)):
