def getMinDiff(arr, n, k):
    if n == 1:
        return 0
    arr.sort()
    ans = arr[-1] - arr[0]
    small = arr[0] + k
    big = arr[-1] - k
    if small > big:
        small, big = big, small
    for i in range(1, n - 1):
        subtract = arr[i] - k
        add = arr[i] + k
        # If both subtraction and addition are within current bounds, nothing to do.
        if subtract >= small or add <= big:
            continue
        # Decide whether to adjust the lower bound or upper bound.
        if big - subtract <= add - small:
            small = subtract
        else:
            big = add
    return min(ans, big - small)

