def minJumps(arr, n):
    # Initialize the jumps array with default 0 values
    jumps = [0] * n
    # Last index requires no jumps to reach the end
    jumps[n - 1] = 0
    # Process the array backwards from the second last element to the first
    for i in range(n - 2, -1, -1):
        # If arr[i] is 0, we cannot jump anywhere from that position
        if arr[i] == 0:
            jumps[i] = float('inf')
        # If we can jump directly to or beyond the last index from current index
        elif arr[i] >= n - i - 1:
            jumps[i] = 1
        else:
            min_val = float('inf')
            # Check all positions reachable from current index
            for j in range(i + 1, min(n, arr[i] + i + 1)):
                if jumps[j] < min_val:
                    min_val = jumps[j]
            # If a valid path was found, update jumps[i]
            if min_val != float('inf'):
                jumps[i] = min_val + 1
            else:
                jumps[i] = min_val  # Remain infinity if no valid jump was found
    return jumps[0]

