def gcd(a, b):
    if a == 0:
        return b
    if b == 0:
        return a
    k = 0
    # Remove common factors of 2 from both a and b
    while ((a | b) & 1) == 0:
        a >>= 1
        b >>= 1
        k += 1
    # Remove factors of 2 in a
    while (a & 1) == 0:
        a >>= 1
    # Compute the gcd using the binary method
    while b != 0:
        # Remove factors of 2 in b
        while (b & 1) == 0:
            b >>= 1
        # Ensure a is the smaller number
        if a > b:
            a, b = b, a
        b = b - a
    return a << k

