def gcd(a, b):
    if a == b:
        return a
    if a == 0:
        return b
    if b == 0:
        return a
    # If a is even
    if (a & 1) == 0:
        # If b is odd
        if (b & 1) == 1:
            return gcd(a >> 1, b)
        else:  # Both a and b are even
            return gcd(a >> 1, b >> 1) << 1
    # If a is odd and b is even
    if (b & 1) == 0:
        return gcd(a, b >> 1)
    # Both are odd, subtract the smaller from the larger
    if a > b:
        return gcd((a - b) >> 1, b)
    return gcd((b - a) >> 1, a)

