def isSubsetSum(arr, n, target_sum):
    # Create a 2D list of booleans with dimensions 2 x (target_sum + 1)
    subset = [[False] * (target_sum + 1) for _ in range(2)]
    # Loop through from 0 to n (inclusive)
    for i in range(n + 1):
        for j in range(target_sum + 1):
            if j == 0:
                subset[i % 2][j] = True  # Sum 0 is always possible
            elif i == 0:
                subset[i % 2][j] = False  # With 0 items, no sum > 0 is possible
            elif arr[i - 1] <= j:
                # Check if the current sum can be achieved by including the current element
                subset[i % 2][j] = (subset[(i + 1) % 2][j - arr[i - 1]] or 
                                    subset[(i + 1) % 2][j])
            else:
                # Current element cannot be included in the sum
                subset[i % 2][j] = subset[(i + 1) % 2][j]
    return subset[n % 2][target_sum]

