def binomial_coeff_sum(n):
    # Create a table C with dimensions (n+1) x (n+1)
    C = [[0] * (n + 1) for _ in range(n + 1)]
    # Fill in the binomial coefficient table
    for i in range(n + 1):
        # j ranges from 0 to i (since i is always ≤ n in this loop)
        for j in range(i + 1):
            if j == 0 or j == i:
                C[i][j] = 1
            else:
                C[i][j] = C[i - 1][j - 1] + C[i - 1][j]
    # Sum the binomial coefficients from row n
    total = sum(C[n][j] for j in range(n + 1))
    return total

