    for i in range(n):
        left = 0
        right = 0
        # Count valid offerings to the left
        j = i - 1
        while j >= 0:
            if templeHeight[j] < templeHeight[j + 1]:
                left += 1
                j -= 1
            else:
                break
        # Count valid offerings to the right
        j = i + 1
        while j < n:
            if templeHeight[j] < templeHeight[j - 1]:
                right += 1
                j += 1
            else:
