def countTransformation(a: str, b: str) -> int:
    n = len(a)
    m = len(b)
    if m == 0:
        return 1
    # Create a 2D DP table with m rows and n columns initialized to 0
    dp = [[0] * n for _ in range(m)]
    for i in range(m):
        for j in range(i, n):
            if i == 0:
                if j == 0:
                    dp[i][j] = 1 if a[j] == b[i] else 0
                elif a[j] == b[i]:
                    dp[i][j] = dp[i][j - 1] + 1
                else:
                    dp[i][j] = dp[i][j - 1]
            elif a[j] == b[i]:
                dp[i][j] = dp[i][j - 1] + dp[i - 1][j - 1]
            else:
                dp[i][j] = dp[i][j - 1]
    return dp[m - 1][n - 1]

