def is_multiple_of_3(n: int) -> int:
    odd_count = 0
    even_count = 0
    # Make sure n is non-negative
    if n < 0:
        n = -n
    if n == 0:
        return 1
    if n == 1:
        return 0
    # Process the bits of n
    while n != 0:
        if (n & 1) != 0:
            odd_count += 1
        if (n & 2) != 0:
            even_count += 1
        n = n >> 2
    return is_multiple_of_3(abs(odd_count - even_count))

